export const theme3Pt = [
  { textFr: "Comment s'appelle la Constitution actuelle de la France ?", lang: 'pt' as const, text: "Como se chama a Constituição atual da França?", explanation: "A Constituição atual da França é a Constituição da Quinta República, adotada em 4 de outubro de 1958. Ela foi redigida sob o impulso do general de Gaulle e constitui o texto fundamental da organização política francesa.", choices: [{ id: 'a' as const, text: "A Constituição da Quinta República" }, { id: 'b' as const, text: "A Constituição da Quarta República" }, { id: 'c' as const, text: "A Constituição da Terceira República" }, { id: 'd' as const, text: "A Constituição da Sexta República" }] },
  { textFr: "Comment s'appelle le texte qui énonce les droits et devoirs des personnes résidant en France ?", lang: 'pt' as const, text: "Como se chama o texto que enuncia os direitos e deveres das pessoas que residem na França?", explanation: "A Carta dos direitos e deveres do cidadão francês é o texto que enuncia os direitos e deveres das pessoas que residem na França. Ela é entregue aos candidatos à naturalização.", choices: [{ id: 'a' as const, text: "A Carta dos direitos e deveres do cidadão francês" }, { id: 'b' as const, text: "O Código Penal" }, { id: 'c' as const, text: "O Código do Trabalho" }, { id: 'd' as const, text: "A Declaração Universal dos Direitos Humanos" }] },
  { textFr: "Concernant les droits individuels, quelle proposition est correcte ?", lang: 'pt' as const, text: "Sobre os direitos individuais, qual proposição está correta?", explanation: "Na França, cada pessoa possui direitos individuais garantidos pela Constituição e pela Declaração dos Direitos do Homem. Entre esses direitos estão a liberdade de expressão, a liberdade de consciência e o direito à segurança.", choices: [{ id: 'a' as const, text: "Cada pessoa tem o direito de se expressar livremente dentro do respeito à lei" }, { id: 'b' as const, text: "Os direitos individuais dizem respeito apenas aos cidadãos franceses" }, { id: 'c' as const, text: "Os direitos individuais não existem na França" }, { id: 'd' as const, text: "Apenas os homens se beneficiam de direitos individuais" }] },
  { textFr: "De quelle année date la Déclaration des droits de l'homme et du citoyen ?", lang: 'pt' as const, text: "De que ano é a Declaração dos Direitos do Homem e do Cidadão?", explanation: "A Declaração dos Direitos do Homem e do Cidadão foi adotada em 26 de agosto de 1789, durante a Revolução Francesa. Ela é considerada um texto fundador das liberdades na França e no mundo.", choices: [{ id: 'a' as const, text: "1789" }, { id: 'b' as const, text: "1791" }, { id: 'c' as const, text: "1804" }, { id: 'd' as const, text: "1958" }] },
  { textFr: "Lequel de ces droits est un droit fondamental ?", lang: 'pt' as const, text: "Qual destes direitos é um direito fundamental?", explanation: "A liberdade de expressão é um direito fundamental garantido pela Declaração dos Direitos do Homem e do Cidadão de 1789 e pela Constituição francesa. Ela permite que cada um expresse livremente suas ideias e opiniões.", choices: [{ id: 'a' as const, text: "A liberdade de expressão" }, { id: 'b' as const, text: "O direito de dirigir sem habilitação" }, { id: 'c' as const, text: "O direito de não pagar impostos" }, { id: 'd' as const, text: "O direito de não respeitar a lei" }] },
  { textFr: "Parmi ces textes, lequel garantit les droits et libertés en France ?", lang: 'pt' as const, text: "Entre estes textos, qual garante os direitos e liberdades na França?", explanation: "A Declaração dos Direitos do Homem e do Cidadão de 1789 é o texto fundador que garante os direitos e liberdades na França. Ela está integrada ao bloco de constitucionalidade e tem valor constitucional.", choices: [{ id: 'a' as const, text: "A Declaração dos Direitos do Homem e do Cidadão de 1789" }, { id: 'b' as const, text: "O Código de Trânsito" }, { id: 'c' as const, text: "O regulamento interno das empresas" }, { id: 'd' as const, text: "O Código Comercial" }] },
  { textFr: "Qu'est-ce que la liberté d'expression ?", lang: 'pt' as const, text: "O que é a liberdade de expressão?", explanation: "A liberdade de expressão é o direito de cada pessoa de expressar livremente suas opiniões e ideias, dentro do respeito à lei. Ela é garantida pela Declaração dos Direitos do Homem e do Cidadão de 1789.", choices: [{ id: 'a' as const, text: "O direito de expressar livremente suas opiniões dentro do respeito à lei" }, { id: 'b' as const, text: "O direito de dizer tudo o que se quer sem nenhum limite" }, { id: 'c' as const, text: "O direito de publicar informações secretas do Estado" }, { id: 'd' as const, text: "O direito reservado apenas aos jornalistas" }] },
  { textFr: "Quel droit permet à une personne de se défendre devant la justice ?", lang: 'pt' as const, text: "Qual direito permite que uma pessoa se defenda perante a justiça?", explanation: "O direito à defesa permite que qualquer pessoa se defenda perante a justiça, seja assistida por um advogado e tenha um julgamento justo. É um direito fundamental garantido pela Constituição.", choices: [{ id: 'a' as const, text: "O direito à defesa" }, { id: 'b' as const, text: "O direito de greve" }, { id: 'c' as const, text: "O direito de voto" }, { id: 'd' as const, text: "O direito de manifestação" }] },
  { textFr: "Quel est le texte fondateur établissant les droits et les devoirs de chaque citoyen ?", lang: 'pt' as const, text: "Qual é o texto fundador que estabelece os direitos e deveres de cada cidadão?", explanation: "A Declaração dos Direitos do Homem e do Cidadão de 1789 é o texto fundador que estabelece os direitos e deveres de cada cidadão. Ela foi adotada durante a Revolução Francesa e faz parte do bloco de constitucionalidade.", choices: [{ id: 'a' as const, text: "A Declaração dos Direitos do Homem e do Cidadão de 1789" }, { id: 'b' as const, text: "O Código Civil de 1804" }, { id: 'c' as const, text: "A Constituição de 1958" }, { id: 'd' as const, text: "O Tratado de Maastricht" }] },
  { textFr: "Quel texte a été adopté pendant la Révolution française ?", lang: 'pt' as const, text: "Qual texto foi adotado durante a Revolução Francesa?", explanation: "A Declaração dos Direitos do Homem e do Cidadão foi adotada em 26 de agosto de 1789, durante a Revolução Francesa. Ela proclama os direitos naturais e imprescritíveis do homem.", choices: [{ id: 'a' as const, text: "A Declaração dos Direitos do Homem e do Cidadão" }, { id: 'b' as const, text: "A Constituição da Quinta República" }, { id: 'c' as const, text: "O Código Civil" }, { id: 'd' as const, text: "O Tratado de Versalhes" }] },
  { textFr: "Quelle liberté permet à une personne de ne pas avoir de religion ?", lang: 'pt' as const, text: "Qual liberdade permite que uma pessoa não tenha religião?", explanation: "A liberdade de consciência permite que cada um creia ou não creia em uma religião. Ela é garantida pela lei de 1905 sobre a separação entre Igreja e Estado e pela Constituição francesa.", choices: [{ id: 'a' as const, text: "A liberdade de consciência" }, { id: 'b' as const, text: "A liberdade de expressão" }, { id: 'c' as const, text: "A liberdade de imprensa" }, { id: 'd' as const, text: "A liberdade de circulação" }] },
  { textFr: "Une femme peut avorter :", lang: 'pt' as const, text: "Uma mulher pode abortar:", explanation: "Na França, uma mulher pode abortar livremente até 14 semanas de gestação (desde a lei de 2 de março de 2022). Esse direito é garantido por lei e foi constitucionalizado em 2024.", choices: [{ id: 'a' as const, text: "Livremente, dentro dos prazos previstos por lei" }, { id: 'b' as const, text: "Somente com a autorização do marido" }, { id: 'c' as const, text: "Apenas em caso de perigo para sua vida" }, { id: 'd' as const, text: "O aborto é proibido na França" }] },
  { textFr: "Est-il toujours possible de divorcer ?", lang: 'pt' as const, text: "É sempre possível se divorciar?", explanation: "Sim, na França, é sempre possível se divorciar. O divórcio pode ser solicitado por um ou ambos os cônjuges. Existem vários procedimentos: por consentimento mútuo, por culpa, por alteração definitiva do vínculo conjugal, etc.", choices: [{ id: 'a' as const, text: "Sim, o divórcio é sempre possível na França" }, { id: 'b' as const, text: "Não, o divórcio é proibido na França" }, { id: 'c' as const, text: "Somente se ambos os cônjuges concordarem" }, { id: 'd' as const, text: "Somente após 10 anos de casamento" }] },
  { textFr: "La peine de mort est :", lang: 'pt' as const, text: "A pena de morte é:", explanation: "A pena de morte foi abolida na França em 9 de outubro de 1981, sob a presidência de François Mitterrand, graças à ação do Ministro da Justiça Robert Badinter. Sua abolição está inscrita na Constituição desde 2007.", choices: [{ id: 'a' as const, text: "Abolida na França desde 1981" }, { id: 'b' as const, text: "Ainda aplicada para os crimes mais graves" }, { id: 'c' as const, text: "Autorizada apenas em tempo de guerra" }, { id: 'd' as const, text: "Suspensa temporariamente" }] },
  { textFr: "Concernant les limites aux libertés individuelles, quelle proposition est correcte ?", lang: 'pt' as const, text: "Sobre os limites às liberdades individuais, qual proposição está correta?", explanation: "As liberdades individuais podem ser limitadas para proteger a ordem pública e os direitos de terceiros. Essas limitações devem ser previstas por lei e ser proporcionais ao objetivo perseguido.", choices: [{ id: 'a' as const, text: "As liberdades podem ser limitadas para proteger a ordem pública e os direitos de terceiros" }, { id: 'b' as const, text: "As liberdades individuais são absolutas e nunca podem ser limitadas" }, { id: 'c' as const, text: "Apenas o Presidente pode limitar as liberdades individuais" }, { id: 'd' as const, text: "As liberdades individuais não dizem respeito aos estrangeiros" }] },
  { textFr: "En France, est-ce légal d'être marié à plusieurs personnes en même temps ?", lang: 'pt' as const, text: "Na França, é legal ser casado com várias pessoas ao mesmo tempo?", explanation: "Não, a poligamia é proibida na França. O Código Civil impõe a monogamia: uma pessoa só pode ser casada com uma outra pessoa por vez. A bigamia é um delito punido por lei.", choices: [{ id: 'a' as const, text: "Não, é proibido por lei" }, { id: 'b' as const, text: "Sim, se todas as pessoas concordarem" }, { id: 'c' as const, text: "Sim, mas apenas para os estrangeiros" }, { id: 'd' as const, text: "Sim, desde a lei de 2013" }] },
  { textFr: "Faut-il réduire ses déchets ?", lang: 'pt' as const, text: "É preciso reduzir o lixo?", explanation: "Sim, a redução do lixo é uma obrigação cidadã e ambiental. A Carta do Meio Ambiente, integrada ao bloco de constitucionalidade, prevê que cada um deve contribuir para a preservação do meio ambiente.", choices: [{ id: 'a' as const, text: "Sim, é um dever de cada cidadão para proteger o meio ambiente" }, { id: 'b' as const, text: "Não, não é uma obrigação" }, { id: 'c' as const, text: "Somente se a prefeitura impuser" }, { id: 'd' as const, text: "Não, é papel exclusivo das empresas" }] },
  { textFr: "Jeter une bouteille dans la rue est :", lang: 'pt' as const, text: "Jogar uma garrafa na rua é:", explanation: "Jogar uma garrafa na rua é uma infração punida por lei. Trata-se de descarte irregular de lixo, passível de multa. Cada um deve respeitar a limpeza dos espaços públicos.", choices: [{ id: 'a' as const, text: "Proibido e passível de multa" }, { id: 'b' as const, text: "Permitido se a garrafa for de plástico" }, { id: 'c' as const, text: "Tolerado nas grandes cidades" }, { id: 'd' as const, text: "Permitido se não houver lixeira por perto" }] },
  { textFr: "Pourquoi les libertés individuelles peuvent-elles être limitées ?", lang: 'pt' as const, text: "Por que as liberdades individuais podem ser limitadas?", explanation: "As liberdades individuais podem ser limitadas para preservar a ordem pública e proteger os direitos e liberdades de terceiros. A lei fixa esses limites de maneira proporcional.", choices: [{ id: 'a' as const, text: "Para preservar a ordem pública e proteger os direitos de terceiros" }, { id: 'b' as const, text: "Para favorecer o governo no poder" }, { id: 'c' as const, text: "Para impedir os cidadãos de se expressarem" }, { id: 'd' as const, text: "As liberdades individuais nunca podem ser limitadas" }] },
  { textFr: "Que doit faire une personne en cas d'accident ?", lang: 'pt' as const, text: "O que uma pessoa deve fazer em caso de acidente?", explanation: "Em caso de acidente, qualquer pessoa deve chamar o socorro (o 15 para o SAMU, o 18 para os bombeiros ou o 112 para o número de emergência europeu) e prestar assistência às vítimas na medida do possível.", choices: [{ id: 'a' as const, text: "Chamar o socorro e prestar assistência às vítimas" }, { id: 'b' as const, text: "Continuar seu caminho sem parar" }, { id: 'c' as const, text: "Filmar a cena e publicar nas redes sociais" }, { id: 'd' as const, text: "Esperar que outra pessoa intervenha" }] },
  { textFr: "Que permet la citoyenneté française ?", lang: 'pt' as const, text: "O que a cidadania francesa permite?", explanation: "A cidadania francesa permite participar da vida política do país, especialmente pelo direito de voto e o direito de ser eleito. Ela confere também direitos civis e sociais e implica deveres.", choices: [{ id: 'a' as const, text: "Votar e participar da vida política do país" }, { id: 'b' as const, text: "Não pagar impostos" }, { id: 'c' as const, text: "Não respeitar as leis francesas" }, { id: 'd' as const, text: "Ter um emprego garantido pelo Estado" }] },
  { textFr: "Que risque une personne qui ne respecte pas la loi ?", lang: 'pt' as const, text: "O que uma pessoa que não respeita a lei pode sofrer?", explanation: "Uma pessoa que não respeita a lei está sujeita a sanções penais que podem ir de multa a prisão, dependendo da gravidade da infração cometida (contravenção, delito ou crime).", choices: [{ id: 'a' as const, text: "Sanções que podem ir de multa a prisão" }, { id: 'b' as const, text: "Nada, não há sanção na França" }, { id: 'c' as const, text: "Apenas uma advertência verbal" }, { id: 'd' as const, text: "A expulsão automática do território" }] },
  { textFr: "Quel est le rôle de la gendarmerie ?", lang: 'pt' as const, text: "Qual é o papel da gendarmaria?", explanation: "A gendarmaria nacional garante a manutenção da ordem pública e a segurança das pessoas, principalmente nas zonas rurais e periurbanas. Ela está vinculada ao Ministério do Interior.", choices: [{ id: 'a' as const, text: "Garantir a segurança das pessoas e manter a ordem, principalmente em zona rural" }, { id: 'b' as const, text: "Administrar os impostos dos cidadãos" }, { id: 'c' as const, text: "Julgar as pessoas acusadas de crimes" }, { id: 'd' as const, text: "Redigir as leis" }] },
  { textFr: "Quel est le rôle de la police ?", lang: 'pt' as const, text: "Qual é o papel da polícia?", explanation: "A polícia nacional garante a manutenção da ordem pública e a segurança das pessoas, principalmente em zona urbana. Ela zela pelo respeito às leis e protege os cidadãos.", choices: [{ id: 'a' as const, text: "Garantir a segurança das pessoas e manter a ordem pública" }, { id: 'b' as const, text: "Votar as leis no Parlamento" }, { id: 'c' as const, text: "Cobrar os impostos" }, { id: 'd' as const, text: "Dirigir os hospitais" }] },
  { textFr: "Qu'est-ce qu'une infraction ?", lang: 'pt' as const, text: "O que é uma infração?", explanation: "Uma infração é um comportamento proibido por lei e punido com sanções penais. Existem três categorias de infrações na França: as contravenções, os delitos e os crimes, classificados por ordem de gravidade.", choices: [{ id: 'a' as const, text: "Um comportamento proibido por lei e punido com sanções penais" }, { id: 'b' as const, text: "Uma regra de educação não respeitada" }, { id: 'c' as const, text: "Um desacordo entre duas pessoas" }, { id: 'd' as const, text: "Uma opinião política controversa" }] },
  { textFr: "Comment peut-on réduire ses déchets ?", lang: 'pt' as const, text: "Como se pode reduzir o lixo?", explanation: "Pode-se reduzir o lixo separando, reciclando, compostando, evitando o desperdício de alimentos e priorizando produtos com menos embalagens. A coleta seletiva é um gesto cidadão essencial.", choices: [{ id: 'a' as const, text: "Separando, reciclando e reduzindo o desperdício" }, { id: 'b' as const, text: "Jogando tudo na mesma lixeira" }, { id: 'c' as const, text: "Queimando o lixo no quintal" }, { id: 'd' as const, text: "Despejando-o na natureza" }] },
  { textFr: "Déposer une machine à laver cassée sur le trottoir est :", lang: 'pt' as const, text: "Deixar uma máquina de lavar quebrada na calçada é:", explanation: "Deixar um objeto volumoso na calçada é proibido e constitui descarte irregular passível de multa. Deve-se levar os objetos volumosos ao ecoponto ou solicitar o serviço de coleta da prefeitura.", choices: [{ id: 'a' as const, text: "Proibido e passível de multa" }, { id: 'b' as const, text: "Permitido se for à noite" }, { id: 'c' as const, text: "Permitido nas grandes cidades" }, { id: 'd' as const, text: "Permitido se deixar um bilhete de desculpas" }] },
  { textFr: "En quoi consiste la traite des êtres humains ?", lang: 'pt' as const, text: "Em que consiste o tráfico de seres humanos?", explanation: "O tráfico de seres humanos consiste em recrutar, transportar ou alojar uma pessoa para fins de exploração (trabalho forçado, exploração sexual, etc.). É um crime severamente punido pela lei francesa.", choices: [{ id: 'a' as const, text: "Explorar pessoas para fins de trabalho forçado, exploração sexual ou outros" }, { id: 'b' as const, text: "Fazer comércio internacional de mercadorias" }, { id: 'c' as const, text: "Transportar pessoas de um país a outro legalmente" }, { id: 'd' as const, text: "Contratar trabalhadores estrangeiros com contrato de trabalho" }] },
  { textFr: "Que doit faire une victime de violences ?", lang: 'pt' as const, text: "O que uma vítima de violência deve fazer?", explanation: "Uma vítima de violência deve registrar queixa junto à polícia ou à gendarmaria e, se necessário, ligar para o 17 (socorro policial) ou o 3919 (violência doméstica). Também pode ir à emergência para registrar os ferimentos.", choices: [{ id: 'a' as const, text: "Registrar queixa junto à polícia ou à gendarmaria" }, { id: 'b' as const, text: "Não fazer nada e esperar que passe" }, { id: 'c' as const, text: "Vingar-se sozinha" }, { id: 'd' as const, text: "Sair do país" }] },
  { textFr: "Quelle est l'infraction la plus grave ?", lang: 'pt' as const, text: "Qual é a infração mais grave?", explanation: "O crime é a infração mais grave no direito penal francês. Ele é julgado pelo tribunal do júri e pode ser punido com reclusão criminal que pode chegar à perpétua.", choices: [{ id: 'a' as const, text: "O crime" }, { id: 'b' as const, text: "O delito" }, { id: 'c' as const, text: "A contravenção" }, { id: 'd' as const, text: "A infração menor" }] },
  { textFr: "À quelle liberté la PMA fait-elle référence ?", lang: 'pt' as const, text: "A qual liberdade a PMA faz referência?", explanation: "A procriação medicamente assistida (PMA) faz referência à liberdade de dispor do próprio corpo. Desde a lei de bioética de 2021, a PMA está aberta a todas as mulheres na França.", choices: [{ id: 'a' as const, text: "A liberdade de dispor do próprio corpo" }, { id: 'b' as const, text: "A liberdade de expressão" }, { id: 'c' as const, text: "A liberdade de circulação" }, { id: 'd' as const, text: "A liberdade de imprensa" }] },
  { textFr: "Au nom de quoi l'État justifie-t-il la restriction des droits ?", lang: 'pt' as const, text: "Em nome de quê o Estado justifica a restrição de direitos?", explanation: "O Estado pode restringir certos direitos em nome do interesse geral e da ordem pública. Essas restrições devem ser previstas por lei e proporcionais ao objetivo perseguido.", choices: [{ id: 'a' as const, text: "Em nome do interesse geral e da ordem pública" }, { id: 'b' as const, text: "Em nome do Presidente da República" }, { id: 'c' as const, text: "Em nome dos partidos políticos" }, { id: 'd' as const, text: "Em nome das empresas privadas" }] },
  { textFr: "Concernant le droit de se marier, quelle proposition est correcte ?", lang: 'pt' as const, text: "Sobre o direito de se casar, qual proposição está correta?", explanation: "Na França, toda pessoa maior de idade tem o direito de se casar livremente, inclusive com uma pessoa do mesmo sexo desde a lei de 17 de maio de 2013. O casamento forçado é proibido.", choices: [{ id: 'a' as const, text: "Toda pessoa maior de idade pode se casar livremente, inclusive com uma pessoa do mesmo sexo" }, { id: 'b' as const, text: "O casamento só é possível entre um homem e uma mulher" }, { id: 'c' as const, text: "O casamento necessita da autorização dos pais, mesmo para maiores de idade" }, { id: 'd' as const, text: "O casamento só é possível a partir dos 21 anos" }] },
  { textFr: "Laquelle de ces citations est inscrite dans la Déclaration des droits de l'homme et du citoyen de 1789 ?", lang: 'pt' as const, text: "Qual destas citações está inscrita na Declaração dos Direitos do Homem e do Cidadão de 1789?", explanation: "O artigo 1.º da Declaração dos Direitos do Homem e do Cidadão de 1789 afirma que \"Os homens nascem e permanecem livres e iguais em direitos\". É um dos princípios fundadores da República Francesa.", choices: [{ id: 'a' as const, text: "Os homens nascem e permanecem livres e iguais em direitos" }, { id: 'b' as const, text: "A França é uma monarquia constitucional" }, { id: 'c' as const, text: "O trabalho é obrigatório para todos os cidadãos" }, { id: 'd' as const, text: "A religião católica é a religião oficial da França" }] },
  { textFr: "Le recours à l'avortement est-il autorisé ?", lang: 'pt' as const, text: "O recurso ao aborto é autorizado?", explanation: "Sim, o recurso ao aborto é autorizado na França. A interrupção voluntária da gravidez (IVG) é um direito garantido por lei, realizável até 14 semanas de gestação. Esse direito foi constitucionalizado em 2024.", choices: [{ id: 'a' as const, text: "Sim, é um direito garantido por lei" }, { id: 'b' as const, text: "Não, é totalmente proibido" }, { id: 'c' as const, text: "Apenas em caso de perigo para a mãe" }, { id: 'd' as const, text: "Somente com a autorização de um juiz" }] },
  { textFr: "Que contient la Constitution ?", lang: 'pt' as const, text: "O que contém a Constituição?", explanation: "A Constituição contém as regras fundamentais de organização do Estado, a distribuição dos poderes e os direitos e liberdades fundamentais dos cidadãos. Ela é a norma jurídica suprema na França.", choices: [{ id: 'a' as const, text: "As regras de organização do Estado e os direitos fundamentais dos cidadãos" }, { id: 'b' as const, text: "Apenas as leis penais" }, { id: 'c' as const, text: "As regras do Código de Trânsito" }, { id: 'd' as const, text: "A lista de impostos a pagar" }] },
  { textFr: "Que garantit la liberté de la presse ?", lang: 'pt' as const, text: "O que a liberdade de imprensa garante?", explanation: "A liberdade de imprensa garante o direito de informar e de ser informado livremente. Ela é consagrada pela lei de 29 de julho de 1881 e constitui um pilar da democracia francesa.", choices: [{ id: 'a' as const, text: "O direito de informar e de ser informado livremente" }, { id: 'b' as const, text: "O direito de publicar notícias falsas" }, { id: 'c' as const, text: "O direito de difamar qualquer pessoa pública" }, { id: 'd' as const, text: "O direito de não respeitar a vida privada" }] },
  { textFr: "Que prévoit la Charte de l'environnement ?", lang: 'pt' as const, text: "O que prevê a Carta do Meio Ambiente?", explanation: "A Carta do Meio Ambiente, integrada ao bloco de constitucionalidade em 2005, prevê que cada um tem o direito de viver em um ambiente equilibrado e respeitoso com a saúde, e o dever de preservar o meio ambiente.", choices: [{ id: 'a' as const, text: "O direito de viver em um ambiente saudável e o dever de preservá-lo" }, { id: 'b' as const, text: "A proibição total da indústria na França" }, { id: 'c' as const, text: "O direito de poluir se pagar uma taxa" }, { id: 'd' as const, text: "A obrigação de viver no campo" }] },
  { textFr: "Que signifie la dignité humaine ?", lang: 'pt' as const, text: "O que significa a dignidade humana?", explanation: "A dignidade humana significa que todo ser humano tem um valor intrínseco que deve ser respeitado. Esse princípio proíbe tratamentos degradantes, desumanos ou cruéis e constitui um direito fundamental.", choices: [{ id: 'a' as const, text: "Que todo ser humano tem um valor que deve ser respeitado e protegido" }, { id: 'b' as const, text: "Que apenas os cidadãos franceses merecem respeito" }, { id: 'c' as const, text: "Que a dignidade depende da riqueza de uma pessoa" }, { id: 'd' as const, text: "Que a dignidade é um privilégio concedido pelo Estado" }] },
  { textFr: "Que signifie le droit de manifester ?", lang: 'pt' as const, text: "O que significa o direito de manifestação?", explanation: "O direito de manifestação permite que os cidadãos se reúnam pacificamente no espaço público para expressar uma opinião ou reivindicar um direito. Ele é regulamentado por lei e geralmente necessita de declaração prévia na prefeitura.", choices: [{ id: 'a' as const, text: "O direito de se reunir pacificamente para expressar uma opinião" }, { id: 'b' as const, text: "O direito de bloquear estradas sem autorização" }, { id: 'c' as const, text: "O direito de destruir bens públicos" }, { id: 'd' as const, text: "O direito de recorrer à violência para defender suas ideias" }] },
  { textFr: "Que signifie PMA ?", lang: 'pt' as const, text: "O que significa PMA?", explanation: "PMA significa Procriação Medicamente Assistida. Ela reúne as técnicas médicas que permitem conceber um filho fora do processo natural. Desde 2021, a PMA está aberta a todas as mulheres na França.", choices: [{ id: 'a' as const, text: "Procriação Medicamente Assistida" }, { id: 'b' as const, text: "Proteção Médica Avançada" }, { id: 'c' as const, text: "Prestação Mensal Automática" }, { id: 'd' as const, text: "Programa Médico de Acompanhamento" }] },
  { textFr: "Quel texte est le plus difficile à modifier ?", lang: 'pt' as const, text: "Qual texto é o mais difícil de modificar?", explanation: "A Constituição é o texto mais difícil de modificar. Sua revisão exige ou um voto do Congresso com maioria de 3/5, ou um referendo. É a norma suprema da ordem jurídica francesa.", choices: [{ id: 'a' as const, text: "A Constituição" }, { id: 'b' as const, text: "Uma lei ordinária" }, { id: 'c' as const, text: "Um decreto" }, { id: 'd' as const, text: "Uma portaria municipal" }] },
  { textFr: "Quelle liberté permet à une personne de croire en la religion de son choix ?", lang: 'pt' as const, text: "Qual liberdade permite que uma pessoa creia na religião de sua escolha?", explanation: "A liberdade de consciência e a liberdade de culto permitem que cada pessoa creia na religião de sua escolha ou não creia em nenhuma. Essas liberdades são garantidas pela lei de 1905 e pela Constituição.", choices: [{ id: 'a' as const, text: "A liberdade de consciência e de culto" }, { id: 'b' as const, text: "A liberdade de imprensa" }, { id: 'c' as const, text: "A liberdade de empreender" }, { id: 'd' as const, text: "A liberdade de circulação" }] },
  { textFr: "Qu'est-ce que le droit de grève ?", lang: 'pt' as const, text: "O que é o direito de greve?", explanation: "O direito de greve é o direito dos trabalhadores de cessarem coletivamente o trabalho para defender suas reivindicações profissionais. Ele é reconhecido pelo preâmbulo da Constituição de 1946, integrado ao bloco de constitucionalidade.", choices: [{ id: 'a' as const, text: "O direito de cessar coletivamente o trabalho para defender suas reivindicações profissionais" }, { id: 'b' as const, text: "O direito de nunca trabalhar" }, { id: 'c' as const, text: "O direito de destruir seu local de trabalho" }, { id: 'd' as const, text: "O direito de deixar definitivamente seu emprego sem aviso prévio" }] },
  { textFr: "Qu'est-ce que la Constitution ?", lang: 'pt' as const, text: "O que é a Constituição?", explanation: "A Constituição é o texto jurídico supremo que organiza os poderes do Estado e garante os direitos fundamentais dos cidadãos. A Constituição atual da França data de 4 de outubro de 1958.", choices: [{ id: 'a' as const, text: "O texto jurídico supremo que organiza os poderes do Estado" }, { id: 'b' as const, text: "Uma coletânea de leis penais" }, { id: 'c' as const, text: "O regulamento interno da Assembleia Nacional" }, { id: 'd' as const, text: "Um tratado internacional assinado pela França" }] },
  { textFr: "Qui peut demander à avorter ?", lang: 'pt' as const, text: "Quem pode solicitar um aborto?", explanation: "Toda mulher grávida que não deseja prosseguir com a gestação pode solicitar um aborto, dentro dos prazos previstos por lei (14 semanas de gestação). As menores de idade devem ser acompanhadas por um adulto de sua escolha.", choices: [{ id: 'a' as const, text: "Toda mulher grávida, dentro dos prazos previstos por lei" }, { id: 'b' as const, text: "Apenas mulheres casadas" }, { id: 'c' as const, text: "Apenas mulheres com mais de 25 anos" }, { id: 'd' as const, text: "Apenas por decisão de um juiz" }] },
  { textFr: "Une femme majeure de nationalité française a-t-elle le droit de voter aux élections ?", lang: 'pt' as const, text: "Uma mulher maior de idade de nacionalidade francesa tem o direito de votar nas eleições?", explanation: "Sim, toda mulher maior de idade de nacionalidade francesa tem o direito de votar. O direito de voto das mulheres foi concedido em 1944 na França. O sufrágio é universal e não faz nenhuma distinção de sexo.", choices: [{ id: 'a' as const, text: "Sim, todas as mulheres maiores de idade de nacionalidade francesa têm o direito de votar" }, { id: 'b' as const, text: "Não, apenas os homens podem votar" }, { id: 'c' as const, text: "Somente nas eleições municipais" }, { id: 'd' as const, text: "Somente se tiverem um emprego" }] },
  { textFr: "Concernant l'utilisation des réseaux sociaux, quelle proposition est correcte ?", lang: 'pt' as const, text: "Sobre o uso das redes sociais, qual proposição está correta?", explanation: "O uso das redes sociais está sujeito ao respeito da lei. Discursos racistas, de ódio, difamatórios ou que incitem à violência são proibidos on-line assim como na vida real.", choices: [{ id: 'a' as const, text: "A lei também se aplica nas redes sociais: discursos de ódio ou difamatórios são proibidos" }, { id: 'b' as const, text: "Pode-se dizer tudo o que se quer nas redes sociais sem consequência" }, { id: 'c' as const, text: "As redes sociais não estão sujeitas à lei francesa" }, { id: 'd' as const, text: "Apenas contas verificadas devem respeitar a lei" }] },
  { textFr: "Jeter un mégot par terre est :", lang: 'pt' as const, text: "Jogar uma bituca de cigarro no chão é:", explanation: "Jogar uma bituca de cigarro no chão é uma infração passível de multa de 135 euros. É um gesto poluente que prejudica o meio ambiente e a limpeza dos espaços públicos.", choices: [{ id: 'a' as const, text: "Proibido e passível de multa" }, { id: 'b' as const, text: "Permitido nos espaços públicos" }, { id: 'c' as const, text: "Tolerado se estiver ao ar livre" }, { id: 'd' as const, text: "Proibido apenas nos parques" }] },
  { textFr: "L'État peut-il limiter les droits et libertés ?", lang: 'pt' as const, text: "O Estado pode limitar os direitos e liberdades?", explanation: "Sim, o Estado pode limitar os direitos e liberdades, mas apenas nas condições previstas por lei, por razões de ordem pública, de segurança ou para proteger os direitos de terceiros. Essas limitações devem ser proporcionais.", choices: [{ id: 'a' as const, text: "Sim, nas condições previstas por lei e de maneira proporcional" }, { id: 'b' as const, text: "Não, nunca, as liberdades são absolutas" }, { id: 'c' as const, text: "Sim, sem nenhum limite" }, { id: 'd' as const, text: "Somente em tempo de guerra" }] },
  { textFr: "Parmi ces actions, laquelle permet d'adopter une attitude respectueuse de l'environnement ?", lang: 'pt' as const, text: "Entre estas ações, qual permite adotar uma atitude respeitosa com o meio ambiente?", explanation: "Separar o lixo é um gesto simples e concreto que permite proteger o meio ambiente. A coleta seletiva facilita a reciclagem e reduz a quantidade de lixo enviado a aterros ou incinerado.", choices: [{ id: 'a' as const, text: "Separar o lixo" }, { id: 'b' as const, text: "Jogar o lixo na natureza" }, { id: 'c' as const, text: "Deixar a água correndo permanentemente" }, { id: 'd' as const, text: "Usar o carro para todos os trajetos" }] },
  { textFr: "Quelle proposition constitue une obligation ?", lang: 'pt' as const, text: "Qual proposição constitui uma obrigação?", explanation: "O respeito à lei é uma obrigação para toda pessoa que reside na França, independentemente de sua nacionalidade. Ninguém pode ignorar a lei e cada um deve cumpri-la.", choices: [{ id: 'a' as const, text: "Respeitar a lei" }, { id: 'b' as const, text: "Votar nas eleições" }, { id: 'c' as const, text: "Filiar-se a um partido político" }, { id: 'd' as const, text: "Fazer trabalho voluntário" }] },
  { textFr: "Pour quel motif peut-on limiter la liberté d'expression ?", lang: 'pt' as const, text: "Por qual motivo pode-se limitar a liberdade de expressão?", explanation: "A liberdade de expressão pode ser limitada para prevenir atentados à ordem pública, proteger a reputação ou os direitos de terceiros, e proibir discursos de ódio, racistas ou difamatórios.", choices: [{ id: 'a' as const, text: "Para proteger a ordem pública e os direitos de terceiros" }, { id: 'b' as const, text: "Para impedir qualquer crítica ao governo" }, { id: 'c' as const, text: "Para proibir opiniões religiosas" }, { id: 'd' as const, text: "Nunca se pode limitar a liberdade de expressão" }] },
  { textFr: "Pourquoi doit-on trier ses déchets ?", lang: 'pt' as const, text: "Por que se deve separar o lixo?", explanation: "A separação do lixo é necessária para permitir a reciclagem, reduzir a poluição e preservar os recursos naturais. É uma obrigação cidadã que contribui para a proteção do meio ambiente.", choices: [{ id: 'a' as const, text: "Para permitir a reciclagem e proteger o meio ambiente" }, { id: 'b' as const, text: "Apenas para evitar uma multa" }, { id: 'c' as const, text: "Não é obrigatório" }, { id: 'd' as const, text: "Apenas nas grandes cidades" }] },
  { textFr: "Que doit-on faire face aux ordres des policiers ou gendarmes ?", lang: 'pt' as const, text: "O que se deve fazer diante das ordens dos policiais ou gendarmes?", explanation: "Toda pessoa deve obedecer às ordens legítimas dos policiais e gendarmes. A recusa de cumprir é uma infração penal. Em caso de desacordo, pode-se contestar posteriormente por via legal.", choices: [{ id: 'a' as const, text: "Obedecer às suas ordens legítimas" }, { id: 'b' as const, text: "Ignorá-los sistematicamente" }, { id: 'c' as const, text: "Resistir fisicamente" }, { id: 'd' as const, text: "Fugir sem responder" }] },
  { textFr: "Quel est un exemple d'assistance à personne en danger ?", lang: 'pt' as const, text: "Qual é um exemplo de assistência a pessoa em perigo?", explanation: "Chamar o socorro quando se é testemunha de um acidente é um exemplo de assistência a pessoa em perigo. Na França, não prestar assistência a uma pessoa em perigo é um delito punido por lei.", choices: [{ id: 'a' as const, text: "Chamar o socorro quando se é testemunha de um acidente" }, { id: 'b' as const, text: "Filmar a cena sem intervir" }, { id: 'c' as const, text: "Afastar-se rapidamente do local" }, { id: 'd' as const, text: "Esperar que a polícia chegue sozinha" }] },
  { textFr: "Quel exemple illustre une limitation de liberté pour protéger l'intérêt général ?", lang: 'pt' as const, text: "Qual exemplo ilustra uma limitação de liberdade para proteger o interesse geral?", explanation: "A proibição de fumar em locais públicos fechados é um exemplo de limitação da liberdade individual para proteger a saúde pública e o interesse geral. Essa medida protege os não fumantes do tabagismo passivo.", choices: [{ id: 'a' as const, text: "A proibição de fumar em locais públicos fechados" }, { id: 'b' as const, text: "A proibição de votar" }, { id: 'c' as const, text: "A proibição de falar em público" }, { id: 'd' as const, text: "A proibição de circular livremente" }] },
  { textFr: "Quelle est l'attitude à avoir lorsqu'on est témoin de violences ?", lang: 'pt' as const, text: "Qual é a atitude a ter quando se é testemunha de violência?", explanation: "Quando se é testemunha de violência, deve-se alertar o socorro (polícia, bombeiros, SAMU) e, se possível, prestar assistência à vítima sem se colocar em perigo. Não agir pode constituir um delito de omissão de socorro.", choices: [{ id: 'a' as const, text: "Alertar o socorro e, se possível, prestar assistência à vítima" }, { id: 'b' as const, text: "Filmar a cena e divulgar nas redes sociais" }, { id: 'c' as const, text: "Não fazer nada pois não nos diz respeito" }, { id: 'd' as const, text: "Ir embora imediatamente para não ser envolvido" }] },
  { textFr: "Quelle obligation concerne toutes les personnes résidant en France quelle que soit leur nationalité ?", lang: 'pt' as const, text: "Qual obrigação diz respeito a todas as pessoas que residem na França, independentemente de sua nacionalidade?", explanation: "O respeito à lei francesa é uma obrigação que diz respeito a todas as pessoas que residem na França, independentemente de sua nacionalidade. Ninguém pode alegar desconhecimento da lei em território francês.", choices: [{ id: 'a' as const, text: "O respeito à lei francesa" }, { id: 'b' as const, text: "O voto nas eleições presidenciais" }, { id: 'c' as const, text: "O serviço militar" }, { id: 'd' as const, text: "A filiação a um sindicato" }] },
  { textFr: "Quelle proposition représente un exemple de crime ?", lang: 'pt' as const, text: "Qual proposição representa um exemplo de crime?", explanation: "O assassinato é um exemplo de crime, ou seja, a infração mais grave no direito penal francês. Os crimes são julgados pelo tribunal do júri e punidos com penas de reclusão criminal.", choices: [{ id: 'a' as const, text: "O assassinato" }, { id: 'b' as const, text: "Um excesso de velocidade" }, { id: 'c' as const, text: "Perturbação noturna" }, { id: 'd' as const, text: "Estacionamento proibido" }] },
  { textFr: "Quelle proposition représente un exemple de délit ?", lang: 'pt' as const, text: "Qual proposição representa um exemplo de delito?", explanation: "O furto é um exemplo de delito. Um delito é uma infração de gravidade intermediária, julgada pelo tribunal correcional. É punido com penas de multa e/ou prisão de até 10 anos.", choices: [{ id: 'a' as const, text: "O furto" }, { id: 'b' as const, text: "Um excesso de velocidade de 5 km/h" }, { id: 'c' as const, text: "Perturbação noturna" }, { id: 'd' as const, text: "O homicídio premeditado" }] },
  { textFr: "Qui veille au maintien de l'ordre public ?", lang: 'pt' as const, text: "Quem zela pela manutenção da ordem pública?", explanation: "A polícia e a gendarmaria zelam pela manutenção da ordem pública na França. A polícia atua principalmente em zona urbana e a gendarmaria em zona rural e periurbana.", choices: [{ id: 'a' as const, text: "A polícia e a gendarmaria" }, { id: 'b' as const, text: "Os próprios cidadãos" }, { id: 'c' as const, text: "Apenas os prefeitos" }, { id: 'd' as const, text: "Os advogados" }] },
  { textFr: "S'agissant des déchets, quelle proposition est correcte ?", lang: 'pt' as const, text: "Em relação ao lixo, qual proposição está correta?", explanation: "A separação do lixo é uma obrigação legal na França. Cada cidadão deve separar seu lixo de acordo com as orientações de seu município, a fim de facilitar a reciclagem e proteger o meio ambiente.", choices: [{ id: 'a' as const, text: "A separação do lixo é uma obrigação para proteger o meio ambiente" }, { id: 'b' as const, text: "Pode-se jogar todo o lixo na mesma lixeira" }, { id: 'c' as const, text: "A separação do lixo é facultativa" }, { id: 'd' as const, text: "Apenas as empresas devem separar seu lixo" }] },
  { textFr: "À quoi sert le droit de grève ?", lang: 'pt' as const, text: "Para que serve o direito de greve?", explanation: "O direito de greve permite que os trabalhadores cessem coletivamente o trabalho para defender suas reivindicações profissionais (salários, condições de trabalho, etc.). Ele é garantido pelo preâmbulo da Constituição de 1946.", choices: [{ id: 'a' as const, text: "Permitir que os trabalhadores defendam coletivamente suas reivindicações profissionais" }, { id: 'b' as const, text: "Autorizar os trabalhadores a nunca mais trabalhar" }, { id: 'c' as const, text: "Permitir que os empregadores demitam os trabalhadores insatisfeitos" }, { id: 'd' as const, text: "Obrigar o Estado a aumentar os salários" }] },
  { textFr: "L'article 4 de la Déclaration des droits de l'homme et du citoyen affirme que « la liberté consiste à pouvoir faire tout ce qui ne nuit pas à autrui ». Qu'est-ce que cela signifie ?", lang: 'pt' as const, text: "O artigo 4 da Declaração dos Direitos do Homem e do Cidadão afirma que \"a liberdade consiste em poder fazer tudo o que não prejudique outrem\". O que isso significa?", explanation: "Isso significa que cada um é livre para agir desde que não atente contra os direitos e liberdades dos outros. A liberdade individual termina onde começa a de outrem.", choices: [{ id: 'a' as const, text: "Cada um é livre para agir desde que isso não atente contra os direitos dos outros" }, { id: 'b' as const, text: "Pode-se fazer absolutamente tudo o que se quer" }, { id: 'c' as const, text: "A liberdade não existe na França" }, { id: 'd' as const, text: "Apenas o Estado pode decidir o que é autorizado" }] },
  { textFr: "Que dit l'article 1er de la Constitution française ?", lang: 'pt' as const, text: "O que diz o artigo 1.º da Constituição francesa?", explanation: "O artigo 1.º da Constituição dispõe que a França é uma República indivisível, laica, democrática e social. Ela assegura a igualdade perante a lei de todos os cidadãos sem distinção de origem, raça ou religião.", choices: [{ id: 'a' as const, text: "A França é uma República indivisível, laica, democrática e social" }, { id: 'b' as const, text: "A França é uma monarquia constitucional" }, { id: 'c' as const, text: "O Presidente é eleito por 7 anos" }, { id: 'd' as const, text: "A religião católica é a religião de Estado" }] },
  { textFr: "Que permet la liberté de circulation ?", lang: 'pt' as const, text: "O que permite a liberdade de circulação?", explanation: "A liberdade de circulação permite que qualquer pessoa se desloque livremente pelo território francês e saia dele. Ela é garantida pela Constituição e pelos tratados europeus para os cidadãos da UE.", choices: [{ id: 'a' as const, text: "Deslocar-se livremente pelo território francês" }, { id: 'b' as const, text: "Dirigir sem habilitação" }, { id: 'c' as const, text: "Não respeitar o Código de Trânsito" }, { id: 'd' as const, text: "Circular apenas em seu município de residência" }] },
  { textFr: "Que signifie être citoyen d'un État ?", lang: 'pt' as const, text: "O que significa ser cidadão de um Estado?", explanation: "Ser cidadão de um Estado significa ter direitos (voto, proteção, liberdades) e deveres (respeito à lei, pagamento de impostos, defesa do país) para com esse Estado. A cidadania está ligada à nacionalidade.", choices: [{ id: 'a' as const, text: "Ter direitos e deveres para com esse Estado" }, { id: 'b' as const, text: "Ter apenas direitos sem nenhum dever" }, { id: 'c' as const, text: "Residir no país sem nenhuma obrigação" }, { id: 'd' as const, text: "Ser obrigado a trabalhar para o Estado" }] },
  { textFr: "Que sont les droits fondamentaux ?", lang: 'pt' as const, text: "O que são os direitos fundamentais?", explanation: "Os direitos fundamentais são os direitos essenciais garantidos a cada indivíduo, como a liberdade, a igualdade, a dignidade e a segurança. Eles são protegidos pela Constituição e pelos textos internacionais.", choices: [{ id: 'a' as const, text: "Os direitos essenciais garantidos a cada indivíduo, como a liberdade e a igualdade" }, { id: 'b' as const, text: "Os direitos reservados aos funcionários públicos" }, { id: 'c' as const, text: "Os direitos concedidos apenas pelo Presidente" }, { id: 'd' as const, text: "Os direitos que mudam a cada eleição" }] },
  { textFr: "Quel droit protège une personne contre une arrestation arbitraire ?", lang: 'pt' as const, text: "Qual direito protege uma pessoa contra uma prisão arbitrária?", explanation: "O direito à segurança protege qualquer pessoa contra prisões e detenções arbitrárias. Ele é garantido pela Declaração dos Direitos do Homem e do Cidadão de 1789 e pela Convenção Europeia dos Direitos Humanos.", choices: [{ id: 'a' as const, text: "O direito à segurança" }, { id: 'b' as const, text: "O direito de voto" }, { id: 'c' as const, text: "O direito de greve" }, { id: 'd' as const, text: "O direito à propriedade" }] },
  { textFr: "Quel texte affirme que tous les hommes naissent libres et égaux en droits ?", lang: 'pt' as const, text: "Qual texto afirma que todos os homens nascem livres e iguais em direitos?", explanation: "A Declaração dos Direitos do Homem e do Cidadão de 1789 afirma em seu artigo 1.º que \"Os homens nascem e permanecem livres e iguais em direitos\". É um texto fundador dos direitos humanos.", choices: [{ id: 'a' as const, text: "A Declaração dos Direitos do Homem e do Cidadão de 1789" }, { id: 'b' as const, text: "O Código Civil de 1804" }, { id: 'c' as const, text: "O Tratado de Roma de 1957" }, { id: 'd' as const, text: "A Carta das Nações Unidas de 1945" }] },
  { textFr: "Quelle situation est une atteinte à la dignité humaine ?", lang: 'pt' as const, text: "Qual situação é uma violação da dignidade humana?", explanation: "A escravidão, a tortura e os tratamentos desumanos ou degradantes são violações da dignidade humana. A dignidade humana é um princípio fundamental protegido pela Constituição e pelas convenções internacionais.", choices: [{ id: 'a' as const, text: "A escravidão e a tortura" }, { id: 'b' as const, text: "O direito de voto" }, { id: 'c' as const, text: "O trabalho assalariado" }, { id: 'd' as const, text: "A educação obrigatória" }] },
  { textFr: "Suite à une interpellation par la police, il est possible de :", lang: 'pt' as const, text: "Após uma abordagem policial, é possível:", explanation: "Após uma abordagem, é possível ser colocado em custódia por um período inicial de 24 horas. A pessoa mantém o direito de consultar um advogado e de ser informada de seus direitos.", choices: [{ id: 'a' as const, text: "Ser colocado em custódia e consultar um advogado" }, { id: 'b' as const, text: "Ser preso imediatamente sem julgamento" }, { id: 'c' as const, text: "Recusar dar sua identidade" }, { id: 'd' as const, text: "Sair livremente da delegacia a qualquer momento" }] },
  { textFr: "Tous les citoyens français ont-ils une religion ?", lang: 'pt' as const, text: "Todos os cidadãos franceses têm uma religião?", explanation: "Não, nem todos os cidadãos franceses têm necessariamente uma religião. A França é um Estado laico que garante a liberdade de consciência: cada um é livre para crer ou não crer.", choices: [{ id: 'a' as const, text: "Não, cada um é livre para crer ou não crer" }, { id: 'b' as const, text: "Sim, todos os franceses devem ter uma religião" }, { id: 'c' as const, text: "Sim, a religião católica é obrigatória" }, { id: 'd' as const, text: "Não, a religião é proibida na França" }] },
  { textFr: "À quel âge est la majorité numérique en France ?", lang: 'pt' as const, text: "Com que idade é a maioridade digital na França?", explanation: "A maioridade digital na França é fixada em 15 anos. Abaixo dessa idade, a inscrição nas redes sociais necessita da autorização dos pais. Essa medida visa proteger os menores on-line.", choices: [{ id: 'a' as const, text: "15 anos" }, { id: 'b' as const, text: "13 anos" }, { id: 'c' as const, text: "16 anos" }, { id: 'd' as const, text: "18 anos" }] },
  { textFr: "Dans lequel de ces endroits est-on autorisé à fumer ?", lang: 'pt' as const, text: "Em qual destes locais é permitido fumar?", explanation: "É permitido fumar em espaços privados como a própria residência. Por outro lado, é proibido fumar em locais públicos fechados e cobertos (restaurantes, bares, estações, etc.) desde a lei de 2007.", choices: [{ id: 'a' as const, text: "Em casa, em um espaço privado" }, { id: 'b' as const, text: "Em um restaurante" }, { id: 'c' as const, text: "Em um hospital" }, { id: 'd' as const, text: "Em uma escola" }] },
  { textFr: "En France, la conduite sans permis d'une moto est :", lang: 'pt' as const, text: "Na França, dirigir uma moto sem habilitação é:", explanation: "Dirigir sem habilitação é um delito na França, passível de um ano de prisão e 15.000 euros de multa. A carteira de habilitação é obrigatória para conduzir qualquer veículo motorizado.", choices: [{ id: 'a' as const, text: "Um delito passível de multa e prisão" }, { id: 'b' as const, text: "Permitido se a moto for de baixa cilindrada" }, { id: 'c' as const, text: "Uma simples contravenção" }, { id: 'd' as const, text: "Permitido para trajetos curtos" }] },
  { textFr: "En quoi consiste le devoir de solidarité ?", lang: 'pt' as const, text: "Em que consiste o dever de solidariedade?", explanation: "O dever de solidariedade consiste em contribuir para a coesão social, especialmente pelo pagamento de impostos e contribuições sociais que financiam os serviços públicos e a proteção social para todos.", choices: [{ id: 'a' as const, text: "Contribuir para a coesão social, especialmente pelo pagamento de impostos e contribuições" }, { id: 'b' as const, text: "Dar todo o seu dinheiro para associações" }, { id: 'c' as const, text: "Não fazer nada e esperar a ajuda do Estado" }, { id: 'd' as const, text: "Ajudar apenas as pessoas de sua família" }] },
  { textFr: "Est-ce obligatoire de déclarer ses impôts chaque année en France ?", lang: 'pt' as const, text: "É obrigatório declarar os impostos todos os anos na França?", explanation: "Sim, toda pessoa que reside na França e tem rendimentos é obrigada a declarar seus impostos todos os anos à administração fiscal. É uma obrigação legal, mesmo que não se pague imposto.", choices: [{ id: 'a' as const, text: "Sim, é uma obrigação legal para toda pessoa que reside na França" }, { id: 'b' as const, text: "Não, é facultativo" }, { id: 'c' as const, text: "Somente se ganhar mais de 50.000 euros por ano" }, { id: 'd' as const, text: "Somente para os cidadãos franceses" }] },
  { textFr: "Est-il obligatoire de porter secours à une personne en danger ?", lang: 'pt' as const, text: "É obrigatório socorrer uma pessoa em perigo?", explanation: "Sim, na França, não prestar assistência a uma pessoa em perigo é um delito previsto no artigo 223-6 do Código Penal. Qualquer pessoa que testemunhe um perigo deve agir, no mínimo chamando o socorro.", choices: [{ id: 'a' as const, text: "Sim, a omissão de socorro é um delito" }, { id: 'b' as const, text: "Não, é uma escolha pessoal" }, { id: 'c' as const, text: "Apenas se for médico" }, { id: 'd' as const, text: "Apenas se a pessoa for de nacionalidade francesa" }] },
  { textFr: "Être juré d'assises est :", lang: 'pt' as const, text: "Ser jurado do tribunal do júri é:", explanation: "Ser jurado do tribunal do júri é um dever cívico obrigatório. Os jurados são sorteados das listas eleitorais e participam do julgamento dos crimes mais graves. Recusar sem motivo legítimo é passível de multa.", choices: [{ id: 'a' as const, text: "Um dever cívico obrigatório" }, { id: 'b' as const, text: "Uma escolha voluntária" }, { id: 'c' as const, text: "Reservado aos advogados" }, { id: 'd' as const, text: "Proibido para as mulheres" }] },
  { textFr: "La vente d'alcool en France est interdite aux personnes de moins de :", lang: 'pt' as const, text: "A venda de álcool na França é proibida para pessoas menores de:", explanation: "A venda de álcool é proibida para menores de 18 anos na França. Essa medida visa proteger a saúde dos jovens. Os comerciantes podem solicitar um documento de identidade para verificar a idade.", choices: [{ id: 'a' as const, text: "18 anos" }, { id: 'b' as const, text: "16 anos" }, { id: 'c' as const, text: "21 anos" }, { id: 'd' as const, text: "14 anos" }] },
  { textFr: "Le non-respect du code de la route est :", lang: 'pt' as const, text: "O desrespeito ao código de trânsito é:", explanation: "O desrespeito ao código de trânsito é uma infração que pode ser uma contravenção ou um delito conforme a gravidade. As sanções vão da multa à suspensão da habilitação, podendo chegar à prisão.", choices: [{ id: 'a' as const, text: "Uma infração passível de sanções" }, { id: 'b' as const, text: "Tolerado se for prudente" }, { id: 'c' as const, text: "Sem consequência jurídica" }, { id: 'd' as const, text: "Permitido em caso de urgência pessoal" }] },
  { textFr: "Lequel de ces crimes ou délits peut entraîner la privation des droits civils et politiques par un juge ?", lang: 'pt' as const, text: "Qual destes crimes ou delitos pode acarretar a privação dos direitos civis e políticos por um juiz?", explanation: "Certos crimes ou delitos graves, como a corrupção ou os atentados aos interesses fundamentais da nação, podem acarretar a privação dos direitos civis e políticos (direito de voto, elegibilidade) determinada por um juiz.", choices: [{ id: 'a' as const, text: "Crimes e delitos graves como a corrupção" }, { id: 'b' as const, text: "Um excesso de velocidade" }, { id: 'c' as const, text: "Perturbação noturna" }, { id: 'd' as const, text: "Estacionamento proibido" }] },
  { textFr: "Pour obtenir une carte d'identité, il faut :", lang: 'pt' as const, text: "Para obter uma carteira de identidade, é preciso:", explanation: "Para obter uma carteira de identidade, é preciso fornecer um comprovante de nacionalidade francesa, um comprovante de residência, fotos de identidade e preencher um formulário. A solicitação é feita na prefeitura ou on-line por meio de um pré-cadastro.", choices: [{ id: 'a' as const, text: "Fornecer um comprovante de nacionalidade, um comprovante de residência e fotos de identidade" }, { id: 'b' as const, text: "Simplesmente comparecer à prefeitura sem documentos" }, { id: 'c' as const, text: "Pagar uma quantia de 500 euros" }, { id: 'd' as const, text: "Ter a ficha criminal limpa" }] },
  { textFr: "Que doit faire un citoyen s'il est appelé à être juré dans un procès d'assises ?", lang: 'pt' as const, text: "O que um cidadão deve fazer se for convocado para ser jurado em um julgamento do tribunal do júri?", explanation: "Um cidadão convocado para ser jurado do tribunal do júri deve comparecer ao tribunal. É um dever cívico obrigatório. Recusar sem motivo legítimo é passível de multa de 3.750 euros.", choices: [{ id: 'a' as const, text: "Comparecer ao tribunal pois é um dever cívico obrigatório" }, { id: 'b' as const, text: "Ignorar a convocação pois é facultativo" }, { id: 'c' as const, text: "Enviar outra pessoa em seu lugar" }, { id: 'd' as const, text: "Pedir a um advogado para substituí-lo" }] },
  { textFr: "Quel est l'âge de la majorité civile en France ?", lang: 'pt' as const, text: "Qual é a idade da maioridade civil na França?", explanation: "A maioridade civil na França é fixada em 18 anos. Nessa idade, a pessoa adquire plena capacidade jurídica: pode votar, casar-se sem autorização dos pais, assinar contratos, etc.", choices: [{ id: 'a' as const, text: "18 anos" }, { id: 'b' as const, text: "16 anos" }, { id: 'c' as const, text: "21 anos" }, { id: 'd' as const, text: "15 anos" }] },
  { textFr: "Quel est l'un des devoirs principaux d'un citoyen français ?", lang: 'pt' as const, text: "Qual é um dos deveres principais de um cidadão francês?", explanation: "O respeito à lei é um dos deveres principais de um cidadão francês. Entre os outros deveres estão o pagamento de impostos, a participação na defesa do país e o dever de votar.", choices: [{ id: 'a' as const, text: "Respeitar a lei e pagar seus impostos" }, { id: 'b' as const, text: "Filiar-se a um partido político" }, { id: 'c' as const, text: "Assistir a todas as sessões do Parlamento" }, { id: 'd' as const, text: "Usar um uniforme nacional" }] },
  { textFr: "Qu'est-ce que la citoyenneté numérique ?", lang: 'pt' as const, text: "O que é a cidadania digital?", explanation: "A cidadania digital designa o conjunto de direitos e deveres dos indivíduos no uso das tecnologias digitais. Ela implica um uso responsável da Internet e das redes sociais, respeitando a lei.", choices: [{ id: 'a' as const, text: "O conjunto de direitos e deveres ligados ao uso responsável do digital" }, { id: 'b' as const, text: "O direito de hackear sites da Internet" }, { id: 'c' as const, text: "A obrigação de ter uma conta nas redes sociais" }, { id: 'd' as const, text: "O direito de publicar anonimamente discursos de ódio" }] },
  { textFr: "Qu'est-ce que le devoir de mémoire ?", lang: 'pt' as const, text: "O que é o dever de memória?", explanation: "O dever de memória é a obrigação moral de lembrar dos acontecimentos trágicos da história (guerras, genocídios, etc.) para evitar que se repitam. Ele se manifesta por meio de comemorações e do ensino da história.", choices: [{ id: 'a' as const, text: "A obrigação moral de lembrar dos acontecimentos trágicos da história" }, { id: 'b' as const, text: "A obrigação de memorizar a Constituição" }, { id: 'c' as const, text: "O dever de conhecer todos os presidentes de cor" }, { id: 'd' as const, text: "A obrigação de visitar todos os museus da França" }] },
  { textFr: "Une personne est privée de ses droits civils et politiques pendant 5 ans suite à une condamnation. Parmi ces propositions laquelle est correcte ?", lang: 'pt' as const, text: "Uma pessoa é privada de seus direitos civis e políticos por 5 anos após uma condenação. Entre estas proposições, qual está correta?", explanation: "Quando uma pessoa é privada de seus direitos civis e políticos por decisão judicial, ela não pode mais votar nem se candidatar a uma eleição durante o prazo fixado pelo juiz.", choices: [{ id: 'a' as const, text: "Ela não pode votar nem se candidatar a uma eleição durante 5 anos" }, { id: 'b' as const, text: "Ela pode continuar a votar normalmente" }, { id: 'c' as const, text: "Ela perde apenas o direito de dirigir" }, { id: 'd' as const, text: "Ela deve deixar o território francês" }] },
];
